// src/App.js
import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Education from './components/Education';
import Tests from './components/Tests';
import Analysis from './components/Analysis';
import Trading from './components/Trading';
import Profile from './components/Profile';
import Login from './components/Login';
import './App.css';

function App() {
  const [activeTab, setActiveTab] = useState('education');
  const [progress, setProgress] = useState({ modules: {}, overall_progress: 0 });
  const [testProgress, setTestProgress] = useState({ modules: {}, overall_test_progress: 0 });
  const [tradingState, setTradingState] = useState({
    balance: 10000,
    positions: 0,
    tradeLog: []
  });
  const [isSidebarHidden, setIsSidebarHidden] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');

  // Проверяем наличие токена при загрузке
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      // Для простоты считаем токен валидным (можно добавить проверку на бэкенде)
      setIsAuthenticated(true);
      setUsername(localStorage.getItem('username') || '');
    }
  }, []);

  // Загрузка прогресса из localStorage
  useEffect(() => {
    const savedProgress = localStorage.getItem('progress');
    if (savedProgress) {
      try {
        const parsedProgress = JSON.parse(savedProgress);
        setProgress(parsedProgress);
      } catch (error) {
        console.error("Ошибка при загрузке прогресса из localStorage:", error);
        setProgress({ modules: {}, overall_progress: 0 });
      }
    }
    const savedTestProgress = localStorage.getItem('testProgress');
    if (savedTestProgress) {
      try {
        const parsedTestProgress = JSON.parse(savedTestProgress);
        setTestProgress(parsedTestProgress);
      } catch (error) {
        console.error("Ошибка при загрузке прогресса по тестам из localStorage:", error);
        setTestProgress({ modules: {}, overall_test_progress: 0 });
      }
    }
  }, []);

  // Сохранение прогресса
  useEffect(() => {
    localStorage.setItem('progress', JSON.stringify(progress));
  }, [progress]);

  useEffect(() => {
    localStorage.setItem('testProgress', JSON.stringify(testProgress));
  }, [testProgress]);

  const switchTab = (tabName) => {
    setActiveTab(tabName);
  };

  const toggleRead = (moduleName, isChecked) => {
    setProgress(prevProgress => {
      const updatedModules = {
        ...prevProgress.modules,
        [moduleName]: isChecked
      };
      const completedCount = Object.values(updatedModules).filter(Boolean).length;
      const overall = Math.round((completedCount / Object.keys(modules).length) * 100);
      return {
        modules: updatedModules,
        overall_progress: overall
      };
    });
  };

  const updateTestProgress = (moduleName, passed) => {
    setTestProgress(prevProgress => {
      const updatedModules = {
        ...prevProgress.modules,
        [moduleName]: passed
      };
      const passedCount = Object.values(updatedModules).filter(Boolean).length;
      const overall = Math.round((passedCount / Object.keys(modules).length) * 100);
      return {
        modules: updatedModules,
        overall_test_progress: overall
      };
    });
  };

  const loadData = (parsedData) => {
    // Может использоваться для передачи данных из Analysis в App
  };

  const handleBuyOrder = (amount, price) => {
    setTradingState(prevState => {
      const cost = amount * price;
      if (cost > prevState.balance) {
        alert('Недостаточно средств');
        return prevState;
      }
      return {
        balance: prevState.balance - cost,
        positions: prevState.positions + amount,
        tradeLog: [...prevState.tradeLog, `Куплено ${amount} по ${price.toFixed(2)}`]
      };
    });
  };

  const handleSellOrder = (amount, price) => {
    setTradingState(prevState => {
      if (amount > prevState.positions) {
        alert('Недостаточно позиций для продажи');
        return prevState;
      }
      return {
        balance: prevState.balance + (amount * price),
        positions: prevState.positions - amount,
        tradeLog: [...prevState.tradeLog, `Продано ${amount} по ${price.toFixed(2)}`]
      };
    });
  };

  const toggleSidebar = () => {
    setIsSidebarHidden(!isSidebarHidden);
  };

  const handleLogin = (user) => {
    setIsAuthenticated(true);
    setUsername(user);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('username');
    setIsAuthenticated(false);
    setUsername('');
    setActiveTab('education');
  };

  // --- Исходный объект modules (полностью из вашего первого листинга) ---
  const modules = {
    "Начало начал": {
      title: "Трейдинг и его основы",
      content: `\<h2\>Трейдинг и его основы\</h2\>
\<p\>Трейдинг представляет собой деятельность по покупке и продаже различных финансовых активов с целью получения прибыли. Этот процесс основан на анализе рыночных условий и прогнозировании будущих ценовых движений. Чтобы успешно участвовать в этом процессе, необходимо сначала освоить базовые понятия и правила безопасности.\</p\>
\<h3\>Финансовые рынки\</h3\>
\<p\>Финансовые рынки, где происходит торговля, можно классифицировать на несколько основных типов:\</p\>
\<ul\>
\<li\>\<strong\>Рынок акций (stocks)\</strong\> --- торговля долями (акциями) компаний, таких как Apple или Microsoft.\</li\>
\<li\>\<strong\>Рынок облигаций (bonds)\</strong\> --- торговля долговыми обязательствами.\</li\>
\<li\>\<strong\>Валютный рынок (forex)\</strong\> --- обмен одной валюты на другую (например, EUR/USD). Является крупнейшим в мире.\</li\>
\<li\>\<strong\>Рынок производных инструментов (derivatives)\</strong\> --- торговля контрактами, стоимость которых зависит от базового актива (фьючерсы, опционы).\</li\>
\</ul\>
\<h3\>Понятие \"лот\" и \"позиция\"\</h3\>
\<p\>Центральным элементом любой торговой операции является понятие \<em\>«лот»\</em\>. Лот представляет собой фиксированный объем торгового инструмента, который определяет размер прибыли или убытка за каждую единицу изменения цены. Например, если вы торгуете лотом акций, вы не можете купить одну акцию; вы должны совершить транзакцию минимальным доступным объемом, который и называется лотом. Размер лота напрямую влияет на вашу \<em\>позицию\</em\>, то есть на общее количество активов, которое вы намерены купить или продать в рамках одной сделки. Понимание этого термина критически важно, поскольку от него зависит масштаб ваших потенциальных доходов и убытков.\</p\>
\<h3\>Типы ордеров\</h3\>
\<p\>Механика торговли также включает использование различных типов ордеров, которые являются инструкциями для брокера о том, как выполнять сделки. Наиболее распространенным является \<em\>рыночный ордер\</em\>, который выполняется немедленно по текущей рыночной цене. Однако для управления рисками трейдеры часто используют \<em\>стоп-приказ\</em\> (\<em\>стоп-лосс\</em\>). Это ордер, который закрывает позицию по рыночной цене после того, как цена достигнет заранее установленного уровня убыточности. Например, если вы купили акцию по 100 долларов и опасаетесь её падения, вы можете установить стоп-лосс на уровне 95 долларов. Если цена упадёт до этой отметки, ваша позиция будет автоматически продана, ограничивая ваш убыток на уровне 5 долларов на акцию. Использование стоп-приказов является одним из ключевых правил безопасной торговли.\</p\>
\<h3\>Управление капиталом\</h3\>
\<p\>Еще один фундаментальный принцип --- это \<em\>управление капиталом\</em\>, в частности, адаптация \<em\>размера позиции\</em\>. \<em\>Размер позиции\</em\> --- это количество активов, которое вы готовы купить или продать. Он должен рассчитываться исходя из вашего риска и общего капитала на счёте. Трейдеры должны использовать стоп-приказы для ограничения потенциальных убытков. Кроме того, важен принцип \<em\>соотношения риска к прибыли\</em\>. Перед входом в сделку трейдер должен иметь чёткое представление о потенциальной прибыли и потенциальном убытке, стремясь к тому, чтобы потенциальная прибыль была больше, чем потенциальный убыток. Некоторые эксперты рекомендуют, чтобы стоп-лосс не был установлен ближе чем в 1,5 раза к текущему диапазону высокой/низкой цены (волатильности), так как более близко расположенный стоп-лосс с высокой вероятностью будет сработан без веских причин.\</p\>
\<p\>Эти базовые правила --- использование стоп-приказов, адаптация размера позиции и положительное соотношение риска к прибыли --- формируют основу безопасной и дисциплинированной торговой стратегии, которая позволяет выживать на рынке в долгосрочной перспективе.\</p\>
\<h2\>Справка по ключевым терминам\</h2\>
\<dl\>
\<dt\>Трейдинг\</dt\>
\<dd\>Деятельность по покупке и продаже финансовых активов с целью получения прибыли на основе анализа рынка и прогнозирования ценовых движений.\</dd\>
\<dt\>Финансовые рынки\</dt\>
\<dd\>Площадки, где совершаются сделки с финансовыми инструментами. Основные типы: Рынок акций, Рынок облигаций, Валютный рынок (Forex), Рынок производных инструментов.\</dd\>
\<dt\>Лот\</dt\>
\<dd\>Стандартный или минимальный объём торгового инструмента, в котором совершается сделка. Определяет масштаб потенциальной прибыли или убытка.\</dd\>
\<dt\>Позиция\</dt\>
\<dd\>Объём актива, который трейдер купил («длинная позиция») или продал в расчёте на будущий выкуп («короткая позиция»). Характеризует текущее участие на рынке.\</dd\>
\<dt\>Ордер\</dt\>
\<dd\>Инструкция брокеру на совершение сделки. Основные виды: Рыночный ордер, Стоп-приказ (стоп-лосс).\</dd\>
\<dt\>Управление капиталом\</dt\>
\<dd\>Стратегия распределения средств на торговых операциях с учётом рисков и размера депозита.\</dd\>
\<dt\>Размер позиции\</dt\>
\<dd\>Количество единиц актива, которое трейдер решает купить или продать. Рассчитывается на основе допустимого риска и уровня стоп-лосса.\</dd\>
\<dt\>Соотношение «риск/прибыль»\</dt\>
\<dd\>Соотношение потенциального убытка к потенциальной прибыли по сделке. Рекомендуется, чтобы возможная прибыль превышала возможный убыток (например, 1:2 или лучше).\</dd\>
\<dt\>Волатильность\</dt\>
\<dd\>Мера изменчивости цены актива за определённый период. Высокая волатильность означает большие колебания цены.\</dd\>
\</dl\>`,
