            testProgress={testProgress}
            updateTestProgress={updateTestProgress}
            questions={questions}
            switchTab={switchTab}
          />
        )}
        {activeTab === 'tests' && (
          <Tests
            modules={modules}
            updateTestProgress={updateTestProgress}
            questions={questions}
            testProgress={testProgress}
          />
        )}
        {activeTab === 'analysis' && (
